settings.custom_liquid:
{% if product.metafields.custom.product_features.value %}
    <div class="features_grid">
      {% for feature in product.metafields.custom.product_features.value %}
        <div class="features_card">
           <div class ="features_img">{{ feature.image | image_url: width: 600 | image_tag }}</div>
          <h3 class="features_title">{{ feature.title }}</h3>
          <p class="features_description">{{ feature.description }}</p>
        </div>
      {% endfor %}
    </div>
{% endif %}

{% if product.metafields.custom.product_videos.value != blank %}
  <div class="product-video-list">

    {% for video in product.metafields.custom.product_videos.value %}
      {% render 'video',
        video: video,
        video_autoplay: true,
        video_loop: true,
        section_id: section.id
      %}
    {% endfor %}

  </div>
{% endif %}

{% if product.metafields.custom.product_videos.value != blank %}
  <div class="product-video-list">

    {% for video in product.metafields.custom.product_videos.value %}
      {% render 'video',
        video: video,
        video_autoplay: true,
        video_loop: true,
        section_id: section.id
      %}
    {% endfor %}

  </div>
{% endif %}
